35	template<typename T>
36	void fusedQKV_masked_attention_dispatch(const T*     qkv_buf,
37	                                        const T*     qkv_bias,
38	                                        const T*     relative_attention_bias,
39	                                        T*           key_cache,
40	                                        T*           value_cache,
41	                                        const int*   cache_indir,
42	                                        T*           context_buf,
43	                                        const bool*  finished,
44	                                        const int*   sequence_lengths,
45	                                        const int    max_batch_size,
46	                                        const int    inference_batch_size,
47	                                        const int    beam_width,
48	                                        const int    head_num,
49	                                        const int    size_per_head,
50	                                        const int    rotary_embedding_dim,
51	                                        const bool   neox_rotary_style,
52	                                        const int    memory_max_len,
53	                                        const int*   prefix_prompt_lengths,
54	                                        const int    max_prefix_prompt_length,
55	                                        const int    max_input_len,
56	                                        const int*   total_padding_tokens,
57	                                        const int    step,
58	                                        const float  q_scaling,
59	                                        const int    relative_attention_bias_stride,
60	                                        const T*     linear_bias_slopes,
61	                                        const bool*  masked_tokens,
62	                                        const int*   ia3_tasks,
63	                                        const T*     ia3_key_weights,
64	                                        const T*     ia3_value_weights,
65	                                        const float* qkv_scale_out,
66	                                        const float* attention_out_scale,
67	                                        const int    int8_mode,
68	                                        cudaStream_t stream)
69	{
70	    using DataType = typename SATypeConverter<T>::Type;
71	    // Prepare the parameters.
72	    Masked_multihead_attention_params<DataType> params;
73	    memset(&params, 0, sizeof(params));
74	    int hidden_units = head_num * size_per_head;
75	    if (qkv_bias != nullptr) {
76	        params.q_bias = reinterpret_cast<const DataType*>(qkv_bias);
77	        params.k_bias = reinterpret_cast<const DataType*>(qkv_bias) + hidden_units;
78	        params.v_bias = reinterpret_cast<const DataType*>(qkv_bias) + 2 * hidden_units;
79	    }
80	    else {
81	        params.q_bias = nullptr;
82	        params.k_bias = nullptr;
83	        params.v_bias = nullptr;
84	    }
85	
86	    // Set the output buffer.
87	    params.out = reinterpret_cast<DataType*>(context_buf);
88	
89	    // Set the input buffers.
90	    params.q = reinterpret_cast<const DataType*>(qkv_buf);
91	    if (int8_mode != 2) {
92	        params.k = reinterpret_cast<const DataType*>(qkv_buf) + hidden_units;
93	        params.v = reinterpret_cast<const DataType*>(qkv_buf) + 2 * hidden_units;
94	    }
95	    else {
96	        params.k = reinterpret_cast<const DataType*>(reinterpret_cast<const int8_t*>(qkv_buf) + hidden_units);
97	        params.v = reinterpret_cast<const DataType*>(reinterpret_cast<const int8_t*>(qkv_buf) + 2 * hidden_units);
98	    }
99	    params.stride   = 3 * hidden_units;
100	    params.finished = const_cast<bool*>(finished);
101	
102	    params.k_cache                  = reinterpret_cast<DataType*>(key_cache);
103	    params.v_cache                  = reinterpret_cast<DataType*>(value_cache);
104	    params.cache_indir              = cache_indir;
105	    params.batch_size               = inference_batch_size;
106	    params.beam_width               = beam_width;
107	    params.memory_max_len           = memory_max_len;
108	    params.prefix_prompt_lengths    = prefix_prompt_lengths;
109	    params.max_prefix_prompt_length = max_prefix_prompt_length;
110	    params.length_per_sample        = sequence_lengths;  // max_input_length + current output length
111	    // timestep adding max_prefix_prompt_length for shared memory size calculation and rotary embedding computation
112	    params.timestep             = step + max_prefix_prompt_length - 1;
113	    params.num_heads            = head_num;
114	    params.hidden_size_per_head = size_per_head;
115	    params.rotary_embedding_dim = rotary_embedding_dim;
116	    params.neox_rotary_style    = neox_rotary_style;
117	    // Note: keep norm factor (sqrt(K_dim)) when adopting megatron T5 structure (may adjust)
118	    params.inv_sqrt_dh = 1.F / (sqrtf((float)params.hidden_size_per_head) * q_scaling);
119	
120	    params.total_padding_tokens = total_padding_tokens;
121	    if (relative_attention_bias != nullptr) {
122	        params.relative_attention_bias = reinterpret_cast<const DataType*>(relative_attention_bias);
123	    }
124	    params.relative_attention_bias_stride = relative_attention_bias_stride;
125	    params.masked_tokens                  = masked_tokens;
126	
127	    // The slope of linear position bias per head, e.g., ALiBi.
128	    if (linear_bias_slopes != nullptr) {
129	        params.linear_bias_slopes = reinterpret_cast<const DataType*>(linear_bias_slopes);
130	    }
131	    params.max_input_length = max_input_len;
132	
133	    params.ia3_tasks         = ia3_tasks;
134	    params.ia3_key_weights   = reinterpret_cast<const DataType*>(ia3_key_weights);
135	    params.ia3_value_weights = reinterpret_cast<const DataType*>(ia3_value_weights);
136	
137	    params.int8_mode = int8_mode;
138	    if (int8_mode == 2) {
139	        params.qkv_scale_out       = qkv_scale_out;
140	        params.attention_out_scale = attention_out_scale;
141	    }
142	
143	    PUSH_RANGE("scaled dot-product fusion");
144	    masked_multihead_attention(params, stream);
145	    POP_RANGE;
146	}
