252	DecoderSelfAttentionLayer<T>::DecoderSelfAttentionLayer(size_t           max_batch_size,
253	                                                        size_t           head_num,
254	                                                        size_t           size_per_head,
255	                                                        size_t           local_head_num,
256	                                                        size_t           rotary_embedding_dim,
257	                                                        bool             neox_rotary_style,
258	                                                        size_t           d_model,
259	                                                        const float      q_scaling,
260	                                                        cudaStream_t     stream,
261	                                                        cublasMMWrapper* cublas_wrapper,
262	                                                        IAllocator*      allocator,
263	                                                        bool             is_free_buffer_after_forward,
264	                                                        bool             sparse,
265	                                                        int              int8_mode):
266	    BaseAttentionLayer<T>(stream, cublas_wrapper, allocator, is_free_buffer_after_forward, sparse),
267	    max_batch_size_(max_batch_size),
268	    head_num_(head_num),
269	    size_per_head_(size_per_head),
270	    hidden_units_(head_num_ * size_per_head_),
271	    local_head_num_(local_head_num),
272	    local_hidden_units_(local_head_num_ * size_per_head_),
273	    rotary_embedding_dim_(rotary_embedding_dim),
274	    neox_rotary_style_(neox_rotary_style),
275	    d_model_(d_model),
276	    q_scaling_(q_scaling),
277	    int8_fc_runner_(int8_mode == 2 ? std::make_shared<CutlassInt8GemmRunner<T>>() : nullptr),
278	    int8_mode_(int8_mode)
279	{
280	    FT_CHECK(size_per_head_ == 32 || size_per_head_ == 48 || size_per_head_ == 64 || size_per_head_ == 80
281	             || size_per_head_ == 96 || size_per_head_ == 112 || size_per_head_ == 128 || size_per_head_ == 144
282	             || size_per_head_ == 160 || size_per_head_ == 192 || size_per_head_ == 224 || size_per_head_ == 256);
283	    if (int8_mode_ == 1) {
284	        FT_CHECK_WITH_INFO(!(std::is_same<T, float>::value), "Weight only quant not supported for fp32.");
285	        weight_only_int8_fc_runner_ = std::make_shared<CutlassFpAIntBGemmRunner<T, uint8_t>>();
286	    }
287	}
