41	// The structure of parameters for the masked multihead attention kernel.
42	//
43	// We use the following terminology to describe the different dimensions.
44	//
45	// B:  Batch size (number of sequences),
46	// L:  Sequence length,
47	// D:  Hidden dimension,
48	// H:  Number of heads,
49	// Dh: Hidden dimension per head - Dh = D / H.
50	
51	template<typename T>
52	struct Multihead_attention_params_base {
53	
54	    // The output buffer. Dimensions B x D.
55	    T* out = nullptr;
56	
57	    // The input Qs and the associated bias. Dimensions B x D and D, resp.
58	    const T *q = nullptr, *q_bias = nullptr;
59	    // The input Ks and the associated bias. Dimensions B x D and D, resp.
60	    const T *k = nullptr, *k_bias = nullptr;
61	    // The input Vs and the associated bias. Dimensions B x D and D, resp.
62	    const T *v = nullptr, *v_bias = nullptr;
63	
64	    // The cache for the Ks. The size must be at least B x L x D.
65	    T* k_cache = nullptr;
66	    // The cache for the Vs. The size must be at least B x L x D.
67	    T* v_cache = nullptr;
68	    // The indirections to use for cache when beam sampling.
69	    const int* cache_indir = nullptr;
70	
71	    // scales
72	    const float* query_weight_output_scale               = nullptr;
73	    const float* attention_qk_scale                      = nullptr;
74	    const float* attention_output_weight_input_scale_inv = nullptr;
75	
76	    // Stride to handle the case when KQV is a single buffer
77	    int stride = 0;
78	
79	    // The batch size.
80	    int batch_size = 0;
81	    // The beam width
82	    int beam_width = 0;
83	    // The sequence length.
84	    int memory_max_len = 0;
85	    // The number of heads (H).
86	    int num_heads = 0;
87	    // The hidden dimension per head (Dh).
88	    int hidden_size_per_head = 0;
89	    // The per-head latent space reserved for rotary embeddings.
90	    int  rotary_embedding_dim = 0;
91	    bool neox_rotary_style    = false;
92	    // The maximum length of input sentences.
93	    int max_input_length = 0;
94	    // The current timestep. TODO(bhsueh) Check that do we only this param in cross attention?
95	    int timestep = 0;
96	    // The current timestep of each sentences (support different timestep for different sentences)
97	
98	    // The 1.f / sqrt(Dh). Computed on the host.
99	    float inv_sqrt_dh = 0.0f;
100	
101	    // Used when we have some input context like gpt
102	    const int* total_padding_tokens = nullptr;
103	
104	    const bool* masked_tokens            = nullptr;
105	    const int*  prefix_prompt_lengths    = nullptr;
106	    int         max_prefix_prompt_length = 0;
107	
108	    const T* relative_attention_bias        = nullptr;
109	    int      relative_attention_bias_stride = 0;
110	    // The slope per head of linear position bias to attention score (H).
111	    const T* linear_bias_slopes = nullptr;
112	
113	    const T*   ia3_key_weights   = nullptr;
114	    const T*   ia3_value_weights = nullptr;
115	    const int* ia3_tasks         = nullptr;
116	
117	    const float* qkv_scale_out       = nullptr;
118	    const float* attention_out_scale = nullptr;
119	    int          int8_mode           = 0;
120	};
